async function retry(fn, times = 3) {
  for (let i = 0; i < times; i++) {
    try { return await fn(); } catch (e) {}
  }
  throw new Error('all retries failed');
}

def retry(fn, times=3):
    for i in range(times):
        try:
            return fn()
        except:
            pass
    raise Exception('all retries failed')

public static <T> T retry(Callable<T> fn, int times) throws Exception {
    for (int i = 0; i < times; i++) {
        try { return fn.call(); } catch (Exception e) {}
    }
    throw new Exception("all retries failed");
}

WITH retry_attempts AS (
  SELECT 1 AS attempt
  UNION ALL
  SELECT attempt + 1 FROM retry_attempts WHERE attempt < 3
) SELECT * FROM retry_attempts;
